use std::fs::File;
use std::io::{self, BufRead, BufReader};

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct EepromHw {
    pub name: &'static str,
    pub is_modern: bool,
    pub addr_l: u32,
    pub addr_h: u32,
    pub data: u32,
    pub ctrl: u32,
    pub status: u32,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct SpiHw {
    pub name: &'static str,
    pub data: u32,
    pub status: u32,
    pub ctrl: u32,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct TwiHw {
    pub name: &'static str,
    pub data: u32,
    pub ctrl: u32,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct UartHw {
    pub name: &'static str,
    pub data: u32,
    pub status: u32,
    pub ctrl: u32,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct AdcHw {
    pub name: &'static str,
    /// ADCSRA (control/status: ADEN/ADSC bits).
    pub ctrl: u32,
    /// ADMUX (channel select + ADLAR).
    pub mux: u32,
    /// ADCL / ADCH result registers.
    pub datal: u32,
    pub datah: u32,
}

/// One timer interrupt source: its vector index (0 = none), the TIMSK enable
/// register, the TIFR flag register, and the bit both share.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct TimerIrq {
    pub vector: u8,
    pub enable_reg: u32,
    pub flag_reg: u32,
    pub bit: u8,
}

/// A hardware timer/counter. All register fields are datasheet **I/O** addresses
/// (data address minus 0x20), matching `io_read_raw`/`io_write_raw`. `0` means
/// "no such register". The model advances the counter by the cycles consumed,
/// sets the overflow / output-compare flags, and (when enabled and the global
/// interrupt flag is set) raises the matching vector.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct TimerHw {
    /// 16-bit counter (Timer1) vs 8-bit (Timer0/Timer2).
    pub bits16: bool,
    /// Accumulator slot (0..3) so each timer keeps its own prescaler remainder.
    pub acc: usize,
    /// Register holding the clock-select (CS) bits in its low 3 bits.
    pub clock_reg: u32,
    /// CTC detection: `(io[ctc_reg] & ctc_mask) == ctc_val` means clear-on-OCRA.
    pub ctc_reg: u32,
    pub ctc_mask: u8,
    pub ctc_val: u8,
    pub tcnt: u32,
    pub tcnt_h: u32,
    pub ocra: u32,
    pub ocra_h: u32,
    pub ocrb: u32,
    pub ocrb_h: u32,
    pub ovf: TimerIrq,
    pub compa: TimerIrq,
    pub compb: TimerIrq,
}

const NO_IRQ: TimerIrq = TimerIrq { vector: 0, enable_reg: 0, flag_reg: 0, bit: 0 };

/// One row of the timer table: a device and one of its timers.
#[derive(Debug, Clone, Copy)]
struct TimerEntry {
    device: &'static str,
    hw: TimerHw,
}

