pub fn eeprom_hw(device: &str) -> Option<EepromHw> {
    EEPROM_HW_TABLE.iter().copied().find(|hw| hw.name == device)
}

pub fn spi_hw(device: &str) -> Option<SpiHw> {
    SPI_HW_TABLE.iter().copied().find(|hw| hw.name == device)
}

pub fn twi_hw(device: &str) -> Option<TwiHw> {
    TWI_HW_TABLE.iter().copied().find(|hw| hw.name == device)
}

pub fn uart_hw(device: &str) -> Option<UartHw> {
    UART_HW_TABLE.iter().copied().find(|hw| hw.name == device)
}

