/// A pin-change interrupt group (PCINTn): its vector, the PCICR enable bit, the
/// PCIFR flag bit, the PCMSK per-pin mask register, and the input pin (PINx I/O
/// addr + bit) behind each PCMSK bit. From the avr-libc headers + ATDF pinout.
#[derive(Debug, Clone, Copy)]
pub struct PcIntGroup {
    pub vector: u8,
    pub pcicr: u32,
    pub pcie_bit: u8,
    pub pcifr: u32,
    pub pcif_bit: u8,
    pub pcmsk: u32,
    pub pins: [(u32, u8); 8],
}

